  // Utility: calculate total landed cost for a store (all prices in NOK)
  export function landedCostNOK(priceNOK, shippingNOK = 0) {
    return {
      priceNOK: Math.round(priceNOK),
      shippingNOK: Math.round(shippingNOK),
      total: Math.round(priceNOK + shippingNOK),
    }
  }
